import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { Platform } from '@prisma/client';
import { MatcherService } from '@/lib/services/matcher.service';
import { ComparisonService } from '@/lib/services/comparison.service';
import { PolymarketService } from '@/lib/services/polymarket.service';
import { KalshiService } from '@/lib/services/kalshi.service';

export const dynamic = 'force-dynamic';
export const maxDuration = 20;

const TIMEOUT_MS = 15_000;
const BATCH_SIZE = 10;
const BATCH_DELAY_MS = 200;
const MIN_MATCH_SCORE = 0.75;

type MatchType = 'STRICT' | 'FUZZY' | 'RELATED';

export interface ArbitrageOpportunitiesResponse {
  opportunities: Array<{
    id: string;
    question: string;
    category: string | null;
    roi: number;
    matchScore: number;
    matchType: MatchType;
    polymarket: {
      id: string;
      yesPrice: number;
      noPrice: number;
      effectiveYesPrice: number;
      volume24h: number;
      url: string | null;
    };
    kalshi: {
      id: string;
      yesPrice: number;
      noPrice: number;
      effectiveYesPrice: number;
      volume24h: number;
      url: string | null;
    };
    buyYesOn: Platform;
    buyNoOn: Platform;
    totalVolume24h: number;
    detectedAt: string;
  }>;
  count: number;
  scannedPairs: number;
  generatedAt: string;
}

function effectiveYesPrice(price: number, platform: Platform): number {
  if (platform === 'POLYMARKET') return price * 1.02;
  if (platform === 'KALSHI') return price + 0.07 * (1 - price);
  return price;
}

function effectiveNoPrice(price: number, platform: Platform): number {
  if (platform === 'POLYMARKET') return price * 1.02;
  if (platform === 'KALSHI') return price + 0.07 * (1 - price);
  return price;
}

async function fetchPolymarketPrices(
  externalId: string,
  polyService: PolymarketService
): Promise<{ yesPrice: number; noPrice: number } | null> {
  return polyService.getMarket(externalId);
}

async function fetchKalshiPrices(
  ticker: string,
  kalshiService: KalshiService
): Promise<{ yesPrice: number; noPrice: number } | null> {
  const m = await kalshiService.getMarket(ticker);
  if (!m) return null;
  const yesPrice = m.last_price ?? m.yes_ask ?? m.yes_bid ?? 0.5;
  const noPrice = 1 - yesPrice;
  return { yesPrice, noPrice };
}

export async function GET(req: NextRequest) {
  const generatedAt = new Date().toISOString();
  const searchParams = req.nextUrl.searchParams;
  const minRoiParam = searchParams.get('minRoi') ?? '0.01';
  const category = searchParams.get('category') || undefined;
  const sort = searchParams.get('sort') ?? 'roi';
  const limitParam = searchParams.get('limit') ?? '20';
  const limit = Math.min(Math.max(parseInt(limitParam, 10) || 20, 1), 50);
  const minRoiPercent = parseFloat(minRoiParam) * 100;

  const polyService = new PolymarketService();
  let kalshiService: KalshiService | null = null;
  try {
    kalshiService = new KalshiService();
  } catch {
    // Kalshi auth not configured
  }

  const whereBase = {
    active: true,
    volume24h: { gt: 1000 },
    ...(category && {
      category: { contains: category, mode: 'insensitive' as const }
    })
  };

  const select = {
    id: true,
    platform: true,
    question: true,
    category: true,
    volume24h: true,
    url: true,
    externalId: true,
    slug: true,
    takerFee: true
  };

  const timeoutPromise = new Promise<ArbitrageOpportunitiesResponse>((_, reject) => {
    setTimeout(() => reject(new Error('TIMEOUT')), TIMEOUT_MS);
  });

  const scanPromise = (async (): Promise<ArbitrageOpportunitiesResponse> => {
    const [polyMarkets, kalshiMarkets] = await Promise.all([
      prisma.market.findMany({
        where: { ...whereBase, platform: 'POLYMARKET' },
        orderBy: { volume24h: 'desc' },
        take: 100,
        select
      }),
      prisma.market.findMany({
        where: { ...whereBase, platform: 'KALSHI' },
        orderBy: { volume24h: 'desc' },
        take: 100,
        select
      })
    ]);

    const matcher = new MatcherService();
    const comparisonService = new ComparisonService();

    type Pair = {
      poly: (typeof polyMarkets)[0];
      kalshi: (typeof kalshiMarkets)[0];
      matchScore: number;
      matchType: MatchType;
    };

    const pairs: Pair[] = [];
    for (const poly of polyMarkets) {
      const fullPoly = await prisma.market.findUnique({
        where: { id: poly.id }
      });
      if (!fullPoly) continue;
      const matches = await matcher.findMatches(fullPoly, MIN_MATCH_SCORE);
      for (const m of matches) {
        const kalshiRow = kalshiMarkets.find((k) => k.id === m.market.id);
        if (kalshiRow) {
          pairs.push({
            poly,
            kalshi: kalshiRow,
            matchScore: m.score,
            matchType: (m.matchType as MatchType) || 'RELATED'
          });
          break; // best match only per poly
        }
      }
    }

    const opportunities: ArbitrageOpportunitiesResponse['opportunities'] = [];
    const now = new Date().toISOString();

    for (let i = 0; i < pairs.length; i += BATCH_SIZE) {
      const batch = pairs.slice(i, i + BATCH_SIZE);
      const results = await Promise.allSettled(
        batch.map(async (pair) => {
          const [polyPrices, kalshiPrices] = await Promise.all([
            fetchPolymarketPrices(pair.poly.externalId, polyService),
            kalshiService
              ? fetchKalshiPrices(pair.kalshi.externalId, kalshiService)
              : Promise.resolve(null)
          ]);

          const yesPoly = polyPrices?.yesPrice ?? 0.5;
          const noPoly = polyPrices?.noPrice ?? 0.5;
          const yesKalshi = kalshiPrices?.yesPrice ?? 0.5;
          const noKalshi = kalshiPrices?.noPrice ?? 0.5;

          const polyWithPrices = {
            ...pair.poly,
            platform: 'POLYMARKET' as const,
            yesPrice: yesPoly,
            noPrice: noPoly,
            takerFee: pair.poly.takerFee ?? 0.02
          };
          const kalshiWithPrices = {
            ...pair.kalshi,
            platform: 'KALSHI' as const,
            yesPrice: yesKalshi,
            noPrice: noKalshi,
            takerFee: pair.kalshi.takerFee ?? 0.07
          };

          type MarketLike = Parameters<ComparisonService['detectArbitrage']>[0][number];
          const arbitrage = comparisonService.detectArbitrage([
            polyWithPrices as unknown as MarketLike,
            kalshiWithPrices as unknown as MarketLike
          ]);

          if (!arbitrage || arbitrage.roi < minRoiPercent) return null;

          const effYesPoly = effectiveYesPrice(yesPoly, 'POLYMARKET');
          const effYesKalshi = effectiveYesPrice(yesKalshi, 'KALSHI');
          const effNoPoly = effectiveNoPrice(noPoly, 'POLYMARKET');
          const effNoKalshi = effectiveNoPrice(noKalshi, 'KALSHI');
          const bestYesPlatform = effYesPoly <= effYesKalshi ? 'POLYMARKET' : 'KALSHI';
          const bestNoPlatform = effNoPoly <= effNoKalshi ? 'POLYMARKET' : 'KALSHI';
          const buyYesOn = bestYesPlatform;
          const buyNoOn = bestNoPlatform;

          return {
            id: `${pair.poly.id}-${pair.kalshi.id}`,
            question: pair.poly.question,
            category: pair.poly.category,
            roi: arbitrage.roi,
            matchScore: pair.matchScore,
            matchType: pair.matchType,
            polymarket: {
              id: pair.poly.id,
              yesPrice: yesPoly,
              noPrice: noPoly,
              effectiveYesPrice: effYesPoly,
              volume24h: pair.poly.volume24h,
              url: pair.poly.url
            },
            kalshi: {
              id: pair.kalshi.id,
              yesPrice: yesKalshi,
              noPrice: noKalshi,
              effectiveYesPrice: effYesKalshi,
              volume24h: pair.kalshi.volume24h,
              url: pair.kalshi.url
            },
            buyYesOn: buyYesOn as Platform,
            buyNoOn: buyNoOn as Platform,
            totalVolume24h: pair.poly.volume24h + pair.kalshi.volume24h,
            detectedAt: now
          };
        })
      );

      for (const r of results) {
        if (r.status === 'fulfilled' && r.value) opportunities.push(r.value);
      }

      if (i + BATCH_SIZE < pairs.length) {
        await new Promise((r) => setTimeout(r, BATCH_DELAY_MS));
      }
    }

    if (sort === 'volume') {
      opportunities.sort((a, b) => b.totalVolume24h - a.totalVolume24h);
    } else if (sort === 'newest') {
      opportunities.sort(
        (a, b) => new Date(b.detectedAt).getTime() - new Date(a.detectedAt).getTime()
      );
    } else {
      opportunities.sort((a, b) => b.roi - a.roi);
    }

    const top = opportunities.slice(0, limit);

    return {
      opportunities: top,
      count: top.length,
      scannedPairs: pairs.length,
      generatedAt
    };
  })();

  try {
    const data = await Promise.race([scanPromise, timeoutPromise]);
    return NextResponse.json(data, {
      headers: {
        'Cache-Control': 'public, s-maxage=120, stale-while-revalidate=60'
      }
    });
  } catch (err) {
    if (err instanceof Error && err.message === 'TIMEOUT') {
      return NextResponse.json(
        {
          opportunities: [],
          count: 0,
          scannedPairs: 0,
          generatedAt,
          error: 'Scan timed out after 15s'
        },
        { status: 200 }
      );
    }
    console.error('❌ Arbitrage opportunities error:', err);
    return NextResponse.json(
      {
        opportunities: [],
        count: 0,
        scannedPairs: 0,
        generatedAt,
        error: err instanceof Error ? err.message : 'Unknown error'
      },
      { status: 200 }
    );
  }
}
